ion": "SHOP_NOW", "utm_content": "ad_l1_evergreen_static", "image_url": "https://m.media-amazon.com/images/I/71OBm6QhIKL.__AC_SX300_SY300_QL70_FMwebp_.jpg"}, {"creative_ref": "AD_L2", "headline": "My Kid Hasn''t Put It Down \ud83d\udc09", "body": "Honestly I grabbed this dragon on a whim and it completely blew me away when it arrived \u2014 the detail is *chef''s kiss*. My little one has been carrying it everywhere since it showed up on our doorstep. And it was only $12.99, so I low-key ordered a backup. \ud83d\ude02", "description": "The 3D printed crystal dragon toy my kid is obsessed with \u2014 and it''s only $12.99!", "call_to_action": "SHOP_NOW", "utm_content": "ad_l2_story_static", "image_url": "https://m.media-amazon.com/images/I/71OBm6QhIKL.__AC_SX300_SY300_QL70_FMwebp_.jpg"}, {"creative_ref": "AD_L3", "headline": "Still Thinking About It? \ud83d\udc40\ud83d\udc09", "body": "Hey, just a reminder \u2014 that 12\" crystal dragon is still sitting at $12.99 and it won''t last forever at that price. You already know your kid would lose it over this thing. \ud83d\ude04 Go ahead and grab it before someone else does!", "description": "Don''t let it sell out! The $12.99 crystal dragon toy is still available \u2014 for now.", "call_to_action": "GET_OFFER", "utm_content": "ad_l3_retargeting_static", "image_url": "https://m.media-amazon.com/images/I/71OBm6QhIKL.__AC_SX300_SY300_QL70_FMwebp_.jpg"}]}, "utm_auto": true}', '{}', 1, 'draft', NULL, NULL, NULL, '2026-04-29 11:52:18', '2026-04-29 11:52:18', NULL, NULL);
INSERT INTO public.campaigns_v3 (id, creator_id, package_type, target_type, target_value, brand_slug, product_slug, product_name, destination_url, layers_json, asset_url, asset_type, package_json, defaults_overrides_json, utm_auto, status, meta_campaign_ids_json, meta_post_id, notes, created_at, updated_at, exported_at, built_at) VALUES (4, 'everydaywithsteph', 'new_campaign', 'asin', 'B08GQZ7TCB', 'toy-life', 'toy-life-wooden-train-set-60pc', 'TOY Life Wooden Train Set 60pcs with Magnetic Crane Wooden Train Tracks Toys for Toddlers Boys Girls 3 4 5 3 Year Old Boy Gift Wood Toys Toddler Train for Kids 4-8 - Fits Thomas Brio Chuggington', 'https://www.amazon.com/dp/B08GQZ7TCB?tag=mommymedeals-20', '["L1", "L2", "L3"]', 'https://m.media-amazon.com/images/I/81vGiTqNcTL.__AC_SX300_SY300_QL70_FMwebp_.jpg', 'static_image', '{"package_type": "new_campaign", "ad_account_id": "act_573934886369270", "page_id": "100065251532225", "brand": "toy-life", "product": "TOY Life Wooden Train Set 60pcs with Magnetic Crane Wooden Train Tracks Toys for Toddlers Boys Girls 3 4 5 3 Year Old Boy Gift Wood Toys Toddler Train for Kids 4-8 - Fits Thomas Brio Chuggington", "product_slug": "toy-life-wooden-train-set-60pc", "destination_url": "https://www.amazon.com/dp/B08GQZ7TCB?tag=mommymedeals-20", "layers": [{"layer_id": "L1", "name": "Evergreen", "daily_budget": 2500, "audience_type": "advantage_plus", "creative_ref": "AD_L1"}, {"layer_id": "L2", "name": "Story / Parent Voice", "daily_budget": 2500, "audience_type": "advantage_plus", "creative_ref": "AD_L2"}, {"layer_id": "L3", "name": "Retargeting", "daily_budget": 2500, "audience_type": "retargeting", "creative_ref": "AD_L3", "budget_type": "ABO", "retargeting_source": "page_engagers_14d"}], "creative": {"type": "static_image", "assets": [{"creative_ref": "AD_L1", "headline": "60-Pc Train Set \u2014 Just $36.96", "body": "This TOY Life Wooden Train Set keeps kids 3\u20138 busy for HOURS \u2014 60 pieces, a magnetic crane, and it fits Thomas, Brio & Chuggington tracks. \ud83d\ude82 Parents are obsessed, and honestly the price makes it a no-brainer. Under $37 for a gift they''ll actually play with every single day.", "description": "60-pc wooden train set w/ magnetic crane. Fits Thomas & Brio. Only $36.96 \u2014 great gift for ages 3\u20138!", "call_to_action": "SHOP_NOW", "utm_content": "ad_l1_evergreen_static", "image_url": "https://m.media-amazon.com/images/I/81vGiTqNcTL.__AC_SX300_SY300_QL70_FMwebp_.jpg"}, {"creative_ref": "AD_L2", "headline": "My Son Won''t Put This Down \ud83d\ude82", "body": "I grabbed this TOY Life train set for my 4-year-old and I genuinely did not expect him to be this obsessed \u2014 like, meals are a negotiation now lol. 60 pieces, a magnetic crane, and it hooks right up to his Thomas tracks we already had. $36.96 and it''s honestly one of the best things I''ve bought him.", "description": "A mom-approved wooden train set that connects to Thomas & Brio \u2014 60 pcs for just $36.96. \ud83d\ude0d", "call_to_action": "SHOP_NOW", "utm_content": "ad_l2_story_static", "image_url": "https://m.media-amazon.com/images/I/81vGiTqNcTL.__AC_SX300_SY300_QL70_FMwebp_.jpg"}, {"creative_ref": "AD_L3", "headline": "Still Thinking About This Train Set?", "body": "Hey, just a reminder \u2014 that TOY Life 60-piece wooden train set is still sitting at $36.96 and it''s such a good gift pick for kids 3\u20138. \ud83d\ude82 It connects to Thomas, Brio & Chuggington tracks, so there''s a good chance it works with what you already have. Grab it before it''s gone!", "description": "You looked \u2014 now grab it! 60-pc train set w/ magnetic crane, only $36.96. Fits tracks you already own.", "call_to_action": "GET_OFFER", "utm_content": "ad_l3_retargeting_static", "image_url": "https://m.media-amazon.com/images/I/81vGiTqNcTL.__AC_SX300_SY300_QL70_FMwebp_.jpg"}]}, "utm_auto": true}', '{}', 1, 'exported', NULL, NULL, NULL, '2026-04-29 11:52:29', '2026-05-04 17:24:19', '2026-05-04 17:24:19', NULL);
