INSERT INTO public.collection_content_drafts (id, source_type, source_collection_slug, source_collection_id, creator_id, title, description, voice_source_text, voice_raw_transcript, cleaned_transcript, social_post, landing_intro, hooks_json, cta, platform, tone, product_snapshot_json, status, public_slug, published_collage_slug, created_at, updated_at, published_at, theme, layout) VALUES (6, 'walmart_trend', 'squishy-sensory-fidget-finds', 'squishy-sensory-fidget-finds', 'everydaywithsteph', 'Squishy, Sensory & Fidget Finds', 'Curated Amazon picks for Squishy, Sensory & Fidget Finds.', 'Hey mamas! I pulled together a fun one — squishy, sensory, and fidget finds all in one spot over at Walmart. Whether your kids need something to keep their hands busy, you need a little stress relief yourself, or you''re building out a sensory bin, this collection has something for everyone. From squeeze toys and glitter dumplings to dinosaur digs and finger paints — it''s a great mix for toddlers, older kids, and honestly? Us too.', '', 'Hey mamas! I pulled together a fun one — squishy, sensory, and fidget finds all in one spot over at Walmart. Whether your kids need something to keep their hands busy, you need a little stress relief yourself, or you''re building out a sensory bin, this collection has something for everyone. From squeeze toys and glitter dumplings to dinosaur digs and finger paints — it''s a great mix for toddlers, older kids, and honestly? Us too.', 'Mamas, this one is for the whole house 😄 I just dropped a Squishy, Sensory & Fidget Finds collection over at Walmart and it covers so much ground — sensory bins for toddlers, fidget toys for bigger kids (and let''s be real, for us), Crayola finger paints, Melissa & Doug sticker activities, a balance beam set, and the cutest little squishy toys I''ve ever seen. Whether you''re building out a sensory play shelf, filling Easter baskets, or just need something new to keep the kids entertained, there''s something in here for you. I''ll drop the link below — go take a peek and let me know what catches your eye! [collection link]', 'This Walmart collection is one of my favorites to put together — because it''s the kind of stuff that actually gets used. The Squishy, Sensory & Fidget Finds roundup spans toddler sensory bins from Creativity for Kids, sticker activity sets from Melissa & Doug, Crayola finger paints, balance and movement play from B. toys, and a whole lineup of squishy stress toys that kids and adults both gravitate toward. It''s a mix of calm-down tools, creative play, and just plain fun — all shoppable in one spot at Walmart.', '[{"type": "Fast Discovery", "text": "Found a whole sensory & squishy collection at Walmart and I had to share it with you all immediately \ud83d\udc40"}, {"type": "Problem \u2192 Solution", "text": "Need something to keep little hands busy \u2014 or just need to decompress after a long mom day? This Walmart collection has squishy, sensory, and fidget finds for kids AND adults."}, {"type": "Creator Favorites", "text": "Steph''s picks from the Squishy, Sensory & Fidget collection: the Dinosaur Dig sensory bin for toddlers, the Melissa & Doug Buzz Lightyear Sticker Wow for on-the-go fun, and the glitter dumpling squeeze toys because\u2026 same, honestly."}]', 'Shop Sensory Toys', 'facebook_group', 'warm mom-to-mom', '[{"asin": "B0GX5SN2JG", "product_name": "Jellyfish Squeeze Toys,Jellyfish Squishy,Jelly Fish Squeeze Stress Ball,Ultra Squishy and Moldable Slow Rise,Sensory Toy with a Super Solid Squish for Adult (Blue)", "company_name": "SHANGFEI", "brand": "SHANGFEI", "price": "$14.99", "current_price": "$14.99", "price_display": "$14.99", "image_encoded_string": "https://m.media-amazon.com/images/I/41mm8Oeyn2L._SL500_.jpg", "attribution_link": "https://urlgeni.us/amazon/ycK4Bu", "retailer": "Amazon", "retailer_name": "Amazon", "network": "amazon", "category": "Toy", "item_count": 3158, "source_rank": null, "rank": null, "source_badges": [], "sale_amo