 "sale_amount": 0, "total_earnings": 5.9}]', 'draft', 'walmart-squishy-sensory-fidget-finds', 'walmart-squishy-sensory-fidget-finds', '2026-05-13 18:59:52', '2026-05-13 21:58:15', NULL, 'peach', 'layout-2');
INSERT INTO public.collection_content_drafts (id, source_type, source_collection_slug, source_collection_id, creator_id, title, description, voice_source_text, voice_raw_transcript, cleaned_transcript, social_post, landing_intro, hooks_json, cta, platform, tone, product_snapshot_json, status, public_slug, published_collage_slug, created_at, updated_at, published_at, theme, layout) VALUES (7, 'walmart_trend', 'pok-mon-mario-character-picks', 'pok-mon-mario-character-picks', 'everydaywithsteph', 'Pokémon, Mario & Character Picks', 'Curated Amazon picks for Pokémon, Mario & Character Picks.', 'Pokémon, Mario, Disney Princess, Gabby''s Dollhouse, Toy Story — this collection has the character picks kids are obsessed with right now, all in one place on Amazon. From Pokémon TCG sets and the Bowser''s Castle playset to a Gabby''s Dollhouse water bottle, a Disney Princess flip chair, and that Toy Story Alien Claw Machine (yes, it''s fully functional!), plus outdoor play options like a water table and a wooden climbing playset. Curated these so you don''t have to go hunting — fun finds for little ones across a lot of the characters they love.', '', 'Pokémon, Mario, Disney Princess, Gabby''s Dollhouse, Toy Story — this collection has the character picks kids are obsessed with right now, all in one place on Amazon. From Pokémon TCG sets and the Bowser''s Castle playset to a Gabby''s Dollhouse water bottle, a Disney Princess flip chair, and that Toy Story Alien Claw Machine (yes, it''s fully functional!), plus outdoor play options like a water table and a wooden climbing playset. Curated these so you don''t have to go hunting — fun finds for little ones across a lot of the characters they love.', 'Mamas, I put together a character picks collection on Amazon and it''s a good one! 🎮
INSERT INTO public.collection_content_drafts (id, source_type, source_collection_slug, source_collection_id, creator_id, title, description, voice_source_text, voice_raw_transcript, cleaned_transcript, social_post, landing_intro, hooks_json, cta, platform, tone, product_snapshot_json, status, public_slug, published_collage_slug, created_at, updated_at, published_at, theme, layout) VALUES (8, 'walmart_trend', 'backyard-splash-summer-play', 'backyard-splash-summer-play', 'everydaywithsteph', 'Backyard Splash & Summer Play', 'Curated Amazon picks for Backyard Splash & Summer Play.', 'Backyard Splash & Summer Play collection on Amazon — curated picks for getting the kids outside and having a blast this summer. We''re talking water tables, splash parks, swim goggles, a wooden climbing playset, a cedar sandbox, rocking chairs for the parents watching it all, and more. These are the kinds of finds that make your backyard THE place to be all season long.', '', 'Backyard Splash & Summer Play collection on Amazon — curated picks for getting the kids outside and having a blast this summer. We''re talking water tables, splash parks, swim goggles, a wooden climbing playset, a cedar sandbox, rocking chairs for the parents watching it all, and more. These are the kinds of finds that make your backyard THE place to be all season long.', 'Mamas, I just put together an Amazon collection for summer backyard fun and it is GOOD. 🌊 We''re talking splash parks, water tables, swim goggles, a wooden climbing playset, a cedar sandbox — basically everything you need to make your backyard the coolest spot on the street this summer. I pulled it all into one easy shoppable list so you''re not hunting around. Check it out here → [collection link]', 'Welcome to my Backyard Splash & Summer Play collection on Amazon! I curated these picks with busy moms in mind — the goal was simple: find the best outdoor water and play finds so your kids can have a full summer of backyard adventures without you having to search all over the place. From water tables and splash tunnels to a cedar sandbox and a Montessori climbing playset, there''s something here for every age and every backyard. Scroll through, grab what works for your family, and get that summer started.', '[{"type": "Fast Discovery", "text": "Found a whole Amazon collection of backyard summer play picks and I had to share it immediately \ud83c\udf0a"}, {"type": "Problem \u2192 Solution", "text": "Trying to keep the kids entertained outside all summer without spending every weekend driving somewhere? This Amazon collection has your backyard covered \u2014 water tables, splash parks, a sandbox, and more."}, {"type": "Creator Favorites", "text": "My hand-picked Amazon finds for Backyard Splash & Summer Play \u2014 the ones I''d actually set up in my own yard for the kids this summer."}]', 'Shop the Amazon finds', 'facebook_group', 'warm mom-to-mom', '[{"asin": "B0C75ZS35H", "product_name": "Backyard Waterpark with Splash Wheel, Dump Buckets for Kids Outdoor Water Play", "company_name": "PUDDLE SPLASHERS", "brand": "PUDDLE SPLASHERS", "price": "$119.99", "current_price": "$119.99", "price_display": "$119.99", "image_encoded_string": "https://m.media-amazon.com/images/I/510tGWSvmdL._SL500_.jpg", "attribution_link": "https://urlgeni.us/amazon/UYGiu8", "retailer": "Amazon", "retailer_name": "Amazon", "network": "amazon", "category": "Toy", "item_count": 1422, "source_rank": null, "rank": null, "source_badges": [], "sale_amount": 0, "total_earnings": 149.73}, {"asin": "B0DFHMYT7Q", "product_name": "CoComelon Water Table by Delta Children | 3-Tier Activity Water Play Table with 11-Piece Toy Set | Water Sensory Table + Summer Beach Toys for Outside Backyard for Toddlers Ages 2+, Blue", "company_name": "Visita la tienda de Delta Children", "brand": "Visita la tienda de Delta Children", "price": "$49.99", "current_price": "$49.99", "price_display": "$49.99", "image_encoded_string": "https://m.media-amazon.com/images/I/81