INSERT INTO posts (id, creator_id, asin, network, angle, copy, image_note, collection_slug, status, utm_source, utm_medium, utm_campaign, utm_content, utm_term, smart_link, smart_link_id, smart_link_affiliate_url, smart_link_final_url, product_name, product_brand, product_price, product_image, slug, created_at, updated_at, posted_at, product_availability, product_rating, product_review_count) VALUES (1, 'everydaywithsteph', 'B08C3LF6FK', 'amazon', 'gift-idea', 'okay this is genuinely the cutest gift idea for any kid who loves candy 🍬 it''s a real working vintage candy counter machine for $29.99 and my kids have been obsessed with it since we set it up. way more fun than just handing them a bag of candy, and honestly it keeps them entertained longer than I expected. would be such a hit for a birthday or holiday gift.', 'Nostalgia candy counter machine styled on a kitchen counter with colorful candy inside, warm natural lighting', NULL, 'approved', '', '', '', '', '', '', NULL, NULL, NULL, 'Nostalgia Vintage Hard and Sugar Free Candy Countertop Cotton Candy Maker Includes 2 Reusable Cones And Sugar Scoop – Pink', 'Nostalgia', '$39.99', 'https://m.media-amazon.com/images/I/71gvwKoU+QL._AC_SY300_SX300_.jpg', 'gift-idea-b08c3lf6fk-1', '2026-04-28 13:05:06', '2026-04-28 13:07:43', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO posts (id, creator_id, asin, network, angle, copy, image_note, collection_slug, status, utm_source, utm_medium, utm_campaign, utm_content, utm_term, smart_link, smart_link_id, smart_link_affiliate_url, smart_link_final_url, product_name, product_brand, product_price, product_image, slug, created_at, updated_at, posted_at, product_availability, product_rating, product_review_count) VALUES (2, 'everydaywithsteph', 'B07KJGR9JZ', 'amazon', 'before-after', 'before this fryer I was making the saddest soggy fries in a pan and calling it a win 😅 the Chefman 4.5 liter deep fryer changed everything — crispy fries, fried chicken, donuts, you name it. it''s $62.95 and honestly cheaper than half the takeout orders I was placing because homemade just wasn''t cutting it. the basket strainer makes cleanup so much less of a nightmare too.', 'Chefman deep fryer on a kitchen counter with a basket of golden crispy fries being lifted out, bright kitchen setting', NULL, 'approved', '', '', '', '', '', '', NULL, NULL, NULL, 'Chefman 4.5 Liter Deep Fryer w/Basket Strainer, XL Jumbo Size, Adjustable Temperature & Timer, Perfect for Fried Chicken, Shrimp, French Fries, Chips & More, Removable Oil-Container, Stainless Steel', 'Chefman', '62.95', 'https://m.media-amazon.com/images/I/81CBKZWNKgL.__AC_SX300_SY300_QL70_FMwebp_.jpg', 'before-after-b07kjgr9jz-2', '2026-04-28 13:05:06', '2026-04-28 13:05:44', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO posts (id, creator_id, asin, network, angle, copy, image_note, collection_slug, status, utm_source, utm_medium, utm_campaign, utm_content, utm_term, smart_link, smart_link_id, smart_link_affiliate_url, smart_link_final_url, product_name, product_brand, product_price, product_image, slug, created_at, updated_at, posted_at, product_availability, product_rating, product_review_count) VALUES (3, 'everydaywithsteph', 'B0CMZJB7X6', 'amazon', 'community-reaction', 'I posted this Bluey & Bingo comforter set in my stories and got like 40 DMs asking where it was from — so here it is! it''s a 7-piece full set for $55.98 which is such a good deal compared to buying pieces separately. my daughter saw it and completely lost her mind in the best way. if you''ve got a Bluey kid this is going to make their whole week.', 'Bluey & Bingo comforter set fully made up on a child''s bed with plush toys nearby, bright and cozy kids bedroom', NULL, 'approved', '', '', '', '', '', '', NULL, NULL, NULL, 'Jay Franco Bluey & Bingo Full Comforter Set - 7 Piece Bed Set Includes Sheet Set & Pillow Covers - Super Soft Clouds & Stars Kids Bedding', 'Jay Franco', '55.98', 'https://m.media-amazon.com/images/I/71eKSDujdtL.__AC_SX300_SY300_QL70_FMwebp_.jpg', 'community-reaction-b0cmzjb7x6-3', '2026-04-28 13:05:06', '2026-04-28 13:05:44', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO posts (id, creator_id, asin, network, angle, copy, image_note, collection_slug, status, utm_source, utm_medium, utm_campaign, utm_content, utm_term, smart_link, smart_link_id, smart_link_affiliate_url, smart_link_final_url, product_name, product_brand, product_price, product_image, slug, created_at, updated_at, posted_at, product_availability, product_rating, product_review_count) VALUES (4, 'everydaywithsteph', 'B08GQZ7TCB', 'amazon', 'problem-solve', 'My son used to lose his mind when screen time ended — until I found this 60-piece wooden train set with a magnetic crane for $36.96. He''s been building tracks for an hour straight and hasn''t asked for the tablet once. It grows with them too, works with most major wooden track brands we already had. Honestly wish I''d grabbed it sooner. 🚂', 'toddler boy focused and playing with colorful wooden train tracks on a living room floor, natural light', NULL, 'approved', '', '', '', '', '', '', NULL, NULL, NULL, 'TOY Life Wooden Train Set 60pcs with Magnetic Crane Wooden Train Tracks Toys for Toddlers Boys Girls 3 4 5 3 Year Old Boy Gift Wood Toys Toddler Train for Kids 4-8 - Fits Thomas Brio Chuggington', 'TOY Life', '$36.96', 'https://m.media-amazon.com/images/I/81vGiTqNcTL.__AC_SX300_SY300_QL70_FMwebp_.jpg', 'problem-solve-b08gqz7tcb-4', '2026-04-29 10:54:29', '2026-04-29 10:54:41', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO posts (id, creator_id, asin, network, angle, copy, image_note, collection_slug, status, utm_source, utm_medium, utm_campaign, utm_content, utm_term, smart_link, smart_link_id, smart_link_affiliate_url, smart_link_final_url, product_name, product_brand, product_price, product_image, slug, created_at, updated_at, posted_at, product_availability, product_rating, product_review_count) VALUES (5, 'everydaywithsteph', 'B0DWT2HRSH', 'amazon', 'discovery', 'Okay I just found the coolest thing for dragon-obsessed kids — a 12-inch 3D printed crystal dragon that actually has flexible, poseable segments and it''s only $12.99. My daughter carried it around all afternoon like it was her pet. The detail on this thing is wild for the price, it looks way more expensive than it is. 🐉', 'close-up of the iridescent crystal dragon toy in a child''s hands, showing articulated segments and detail', NULL, 'approved', '', '', '', '', '', '', NULL, NULL, NULL, 'HyBaiS 12 Inch 3D Printed Crystal Dragon Toy,Dragon Figurine Large Toy for Kids', 'HyBaiS', '12.99', 'https://m.media-amazon.com/images/I/71OBm6QhIKL.__AC_SX300_SY300_QL70_FMwebp_.jpg', 'discovery-b0dwt2hrsh-5', '2026-04-29 10:54:29', '2026-04-29 10:54:43', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO posts (id, creator_id, asin, network, angle, copy, image_note, collection_slug, status, utm_source, utm_medium, utm_campaign, utm_content, utm_term, smart_link, smart_link_id, smart_link_affiliate_url, smart_link_final_url, product_name, product_brand, product_price, product_image, slug, created_at, updated_at, posted_at, product_availability, product_rating, product_review_count) VALUES (6, 'everydaywithsteph', 'B0CQMZFP4H', 'amazon', 'community-reaction', 'This one''s been making the rounds in the group and I finally get the hype — so many of you tagged me after grabbing it last month and the reviews in the comments were unreal. If you''ve been on the fence, looks like everyone who tried it is obsessed. Drop a 🙋‍♀️ below if you already have one so the new moms can see!', 'lifestyle flat lay of the product in a cozy home setting, warm tones', NULL, 'archived', '', '', '', '', '', '', NULL, NULL, NULL, '', '', '', 'https://ws-na.amazon-adsystem.com/widgets/q?_encoding=UTF8&ASIN=B0CQMZFP4H&Format=_SL250_&ID=AsinImage&MarketPlace=US&ServiceVersion=20070822&WS=1', 'community-reaction-b0cqmzfp4h-6', '2026-04-29 10:54:29', '2026-05-11 12:33:11', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO posts (id, creator_id, asin, network, angle, copy, image_note, collection_slug, status, utm_source, utm_medium, utm_campaign, utm_content, utm_term, smart_link, smart_link_id, smart_link_affiliate_url, smart_link_final_url, product_name, product_brand, product_price, product_image, slug, created_at, updated_at, posted_at, product_availability, product_rating, product_review_count) VALUES (7, 'everydaywithsteph', 'B08C3LF6FK', 'amazon', 'gift-idea', 'okay this would be such a fun gift for the grandparents who have everything 🎁 it''s a vintage-style candy counter that holds both regular AND sugar free candy so literally everyone is covered. $39.99 and it looks so cute on a counter or in a playroom. my kids would lose their minds if grandma had one of these.', 'retro-style candy dispenser on a kitchen counter with colorful candies visible inside, warm natural lighting', NULL, 'approved', '', '', '', '', '', '', NULL, NULL, NULL, 'Nostalgia Vintage Hard and Sugar Free Candy Countertop Cotton Candy Maker Includes 2 Reusable Cones And Sugar Scoop – Pink', 'Nostalgia', '$39.99', 'https://m.media-amazon.com/images/I/71gvwKoU+QL._AC_SY300_SX300_.jpg', 'gift-idea-b08c3lf6fk-7', '2026-04-29 11:43:31', '2026-04-29 11:43:35', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO posts (id, creator_id, asin, network, angle, copy, image_note, collection_slug, status, utm_source, utm_medium, utm_campaign, utm_content, utm_term, smart_link, smart_link_id, smart_link_affiliate_url, smart_link_final_url, product_name, product_brand, product_price, product_image, slug, created_at, updated_at, posted_at, product_availability, product_rating, product_review_count) VALUES (8, 'everydaywithsteph', 'B0BQNFRNYG', 'amazon', 'problem-solve', 'if you''ve ever lost half a puzzle under the couch you need this 😅 it''s a 1000-piece wooden puzzle board with 4 drawers built in so you can sort pieces and slide the whole thing away when dinner happens. way better than leaving it on the kitchen table for three weeks. $69.99 and honestly it pays for itself in sanity.', 'wooden puzzle board on a living room coffee table with a partially completed puzzle and the storage drawers slightly open showing sorted pieces', NULL, 'approved', '', '', '', '', '', '', NULL, NULL, NULL, '1000 Piece Wooden Jigsaw Puzzle Board - 4 Drawers, Rotating Puzzle Table | 30" X 22" Jigsaw Puzzle Table | Puzzle Cover Included - Portable Puzzle Tables for Adults and Kids by Beyond Innoventions', 'Beyond Innoventions', '69.99', 'https://m.media-amazon.com/images/I/818eQWqm6GL.__AC_SX300_SY300_QL70_FMwebp_.jpg', 'problem-solve-b0bqnfrnyg-8', '2026-04-29 11:43:31', '2026-04-29 11:43:36', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
